/**
 * TOON - Token-Oriented Object Notation
 * A lightweight, token-efficient data format for LLMs
 * 30-60% fewer tokens than JSON
 */

const TOON = {
    /**
     * Convert JSON to TOON format
     * @param {Object|Array} data - JSON data to convert
     * @param {string} name - Collection name (default: 'data')
     * @returns {string} TOON formatted string
     */
    stringify: function(data, name = 'data') {
        if (Array.isArray(data)) {
            return this._arrayToToon(data, name);
        } else if (typeof data === 'object' && data !== null) {
            return this._objectToToon(data, name);
        } else {
            return String(data);
        }
    },

    /**
     * Convert array of objects to TOON
     */
    _arrayToToon: function(arr, name) {
        if (arr.length === 0) return `${name}[0]{}:\n`;

        // Get all unique keys from all objects
        const keys = [...new Set(arr.flatMap(obj =>
            typeof obj === 'object' && obj !== null ? Object.keys(obj) : []
        ))];

        if (keys.length === 0) {
            // Simple array of primitives
            const values = arr.map(v => this._escapeValue(v)).join('\n  ');
            return `${name}[${arr.length}]:\n  ${values}`;
        }

        // Array of objects - tabular format
        const header = `${name}[${arr.length}]{${keys.join(',')}}:`;
        const rows = arr.map(obj => {
            if (typeof obj !== 'object' || obj === null) {
                return '  ' + this._escapeValue(obj);
            }
            return '  ' + keys.map(k => this._escapeValue(obj[k])).join(',');
        });

        return [header, ...rows].join('\n');
    },

    /**
     * Convert single object to TOON
     */
    _objectToToon: function(obj, name) {
        const keys = Object.keys(obj);
        if (keys.length === 0) return `${name}{}:\n`;

        const lines = [`${name}{${keys.join(',')}}:`];
        const values = keys.map(k => this._escapeValue(obj[k])).join(',');
        lines.push('  ' + values);

        return lines.join('\n');
    },

    /**
     * Escape special characters in values
     */
    _escapeValue: function(val) {
        if (val === null || val === undefined) return '';
        if (typeof val === 'object') {
            // Nested object - use inline JSON for deep nesting
            return JSON.stringify(val);
        }
        const str = String(val);
        // Escape commas and newlines in values
        if (str.includes(',') || str.includes('\n') || str.includes('"')) {
            return '"' + str.replace(/"/g, '""') + '"';
        }
        return str;
    },

    /**
     * Parse TOON format back to JSON
     * @param {string} toon - TOON formatted string
     * @returns {Object} Parsed JSON object
     */
    parse: function(toon) {
        const lines = toon.trim().split('\n');
        if (lines.length === 0) return null;

        const headerLine = lines[0];
        const headerMatch = headerLine.match(/^(\w+)(?:\[(\d+)\])?(?:\{([^}]*)\})?:$/);

        if (!headerMatch) {
            throw new Error('Invalid TOON header: ' + headerLine);
        }

        const [, name, countStr, keysStr] = headerMatch;
        const keys = keysStr ? keysStr.split(',').map(k => k.trim()) : [];
        const dataLines = lines.slice(1).filter(l => l.trim());

        if (countStr !== undefined) {
            // Array format
            const result = dataLines.map(line => {
                const values = this._parseLine(line.trim());
                if (keys.length === 0) {
                    return values[0];
                }
                const obj = {};
                keys.forEach((key, i) => {
                    obj[key] = this._parseValue(values[i]);
                });
                return obj;
            });
            return { [name]: result };
        } else {
            // Single object format
            if (dataLines.length === 0) return { [name]: {} };
            const values = this._parseLine(dataLines[0].trim());
            const obj = {};
            keys.forEach((key, i) => {
                obj[key] = this._parseValue(values[i]);
            });
            return { [name]: obj };
        }
    },

    /**
     * Parse a single data line handling quoted values
     */
    _parseLine: function(line) {
        const values = [];
        let current = '';
        let inQuotes = false;

        for (let i = 0; i < line.length; i++) {
            const char = line[i];

            if (char === '"') {
                if (inQuotes && line[i + 1] === '"') {
                    current += '"';
                    i++;
                } else {
                    inQuotes = !inQuotes;
                }
            } else if (char === ',' && !inQuotes) {
                values.push(current);
                current = '';
            } else {
                current += char;
            }
        }
        values.push(current);

        return values;
    },

    /**
     * Parse individual value to appropriate type
     */
    _parseValue: function(val) {
        if (val === undefined || val === '') return null;
        if (val === 'true') return true;
        if (val === 'false') return false;
        if (val === 'null') return null;

        // Try parsing as number
        const num = Number(val);
        if (!isNaN(num) && val.trim() !== '') return num;

        // Try parsing as JSON (for nested objects)
        if ((val.startsWith('{') && val.endsWith('}')) ||
            (val.startsWith('[') && val.endsWith(']'))) {
            try {
                return JSON.parse(val);
            } catch (e) {
                // Not valid JSON, return as string
            }
        }

        return val;
    },

    /**
     * Calculate token savings estimate
     * @param {Object} data - Original JSON data
     * @returns {Object} Stats with JSON size, TOON size, and savings percentage
     */
    tokenSavings: function(data, name = 'data') {
        const jsonStr = JSON.stringify(data);
        const toonStr = this.stringify(data, name);

        // Rough token estimate (chars / 4)
        const jsonTokens = Math.ceil(jsonStr.length / 4);
        const toonTokens = Math.ceil(toonStr.length / 4);
        const savings = ((jsonTokens - toonTokens) / jsonTokens * 100).toFixed(1);

        return {
            jsonChars: jsonStr.length,
            toonChars: toonStr.length,
            jsonTokensEst: jsonTokens,
            toonTokensEst: toonTokens,
            savingsPercent: parseFloat(savings)
        };
    }
};

// Export for Node.js / CommonJS
if (typeof module !== 'undefined' && module.exports) {
    module.exports = TOON;
}

// Export for ES modules
if (typeof window !== 'undefined') {
    window.TOON = TOON;
}

