"""
TOON - Token-Oriented Object Notation
A lightweight, token-efficient data format for LLMs
30-60% fewer tokens than JSON
"""

import json
import re
from typing import Any, Dict, List, Optional, Union


class TOON:
    """TOON parser and serializer for Python"""

    @staticmethod
    def stringify(data: Any, name: str = 'data') -> str:
        """
        Convert Python object to TOON format.

        Args:
            data: Python object (dict, list, or primitive)
            name: Collection name for the output

        Returns:
            TOON formatted string
        """
        if isinstance(data, list):
            return TOON._array_to_toon(data, name)
        elif isinstance(data, dict):
            return TOON._object_to_toon(data, name)
        else:
            return str(data)

    @staticmethod
    def _array_to_toon(arr: List, name: str) -> str:
        """Convert list of objects to TOON tabular format"""
        if not arr:
            return f"{name}[0]{{}}:\n"

        # Get all unique keys from all dicts
        keys = []
        seen = set()
        for obj in arr:
            if isinstance(obj, dict):
                for k in obj.keys():
                    if k not in seen:
                        keys.append(k)
                        seen.add(k)

        if not keys:
            # Simple list of primitives
            values = '\n  '.join(TOON._escape_value(v) for v in arr)
            return f"{name}[{len(arr)}]:\n  {values}"

        # List of dicts - tabular format
        header = f"{name}[{len(arr)}]{{{','.join(keys)}}}:"
        rows = []
        for obj in arr:
            if not isinstance(obj, dict):
                rows.append('  ' + TOON._escape_value(obj))
            else:
                row_values = [TOON._escape_value(obj.get(k)) for k in keys]
                rows.append('  ' + ','.join(row_values))

        return '\n'.join([header] + rows)

    @staticmethod
    def _object_to_toon(obj: Dict, name: str) -> str:
        """Convert single dict to TOON format"""
        if not obj:
            return f"{name}{{}}:\n"

        keys = list(obj.keys())
        header = f"{name}{{{','.join(keys)}}}:"
        values = ','.join(TOON._escape_value(obj[k]) for k in keys)
        return f"{header}\n  {values}"

    @staticmethod
    def _escape_value(val: Any) -> str:
        """Escape special characters in values"""
        if val is None:
            return ''
        if isinstance(val, bool):
            return 'true' if val else 'false'
        if isinstance(val, (dict, list)):
            # Nested structures use inline JSON
            return json.dumps(val)

        s = str(val)
        # Escape commas, newlines, and quotes
        if ',' in s or '\n' in s or '"' in s:
            return '"' + s.replace('"', '""') + '"'
        return s

    @staticmethod
    def parse(toon: str) -> Dict:
        """
        Parse TOON format back to Python object.

        Args:
            toon: TOON formatted string

        Returns:
            Parsed Python dictionary
        """
        lines = toon.strip().split('\n')
        if not lines:
            return {}

        header_line = lines[0]
        header_match = re.match(r'^(\w+)(?:\[(\d+)\])?(?:\{([^}]*)\})?:$', header_line)

        if not header_match:
            raise ValueError(f'Invalid TOON header: {header_line}')

        name = header_match.group(1)
        count_str = header_match.group(2)
        keys_str = header_match.group(3)

        keys = [k.strip() for k in keys_str.split(',')] if keys_str else []
        data_lines = [l.strip() for l in lines[1:] if l.strip()]

        if count_str is not None:
            # Array format
            result = []
            for line in data_lines:
                values = TOON._parse_line(line)
                if not keys:
                    result.append(TOON._parse_value(values[0]) if values else None)
                else:
                    obj = {}
                    for i, key in enumerate(keys):
                        obj[key] = TOON._parse_value(values[i] if i < len(values) else None)
                    result.append(obj)
            return {name: result}
        else:
            # Single object format
            if not data_lines:
                return {name: {}}
            values = TOON._parse_line(data_lines[0])
            obj = {}
            for i, key in enumerate(keys):
                obj[key] = TOON._parse_value(values[i] if i < len(values) else None)
            return {name: obj}

    @staticmethod
    def _parse_line(line: str) -> List[str]:
        """Parse a single data line handling quoted values"""
        values = []
        current = ''
        in_quotes = False
        i = 0

        while i < len(line):
            char = line[i]

            if char == '"':
                if in_quotes and i + 1 < len(line) and line[i + 1] == '"':
                    current += '"'
                    i += 1
                else:
                    in_quotes = not in_quotes
            elif char == ',' and not in_quotes:
                values.append(current)
                current = ''
            else:
                current += char
            i += 1

        values.append(current)
        return values

    @staticmethod
    def _parse_value(val: Optional[str]) -> Any:
        """Parse individual value to appropriate Python type"""
        if val is None or val == '':
            return None
        if val == 'true':
            return True
        if val == 'false':
            return False
        if val == 'null':
            return None

        # Try parsing as number
        try:
            if '.' in val:
                return float(val)
            return int(val)
        except ValueError:
            pass

        # Try parsing as JSON (for nested objects)
        if (val.startswith('{') and val.endswith('}')) or \
           (val.startswith('[') and val.endswith(']')):
            try:
                return json.loads(val)
            except json.JSONDecodeError:
                pass

        return val

    @staticmethod
    def token_savings(data: Any, name: str = 'data') -> Dict[str, Any]:
        """
        Calculate token savings estimate.

        Args:
            data: Original Python data
            name: Collection name

        Returns:
            Dict with JSON size, TOON size, and savings percentage
        """
        json_str = json.dumps(data)
        toon_str = TOON.stringify(data, name)

        # Rough token estimate (chars / 4)
        json_tokens = len(json_str) // 4 + 1
        toon_tokens = len(toon_str) // 4 + 1
        savings = (json_tokens - toon_tokens) / json_tokens * 100

        return {
            'json_chars': len(json_str),
            'toon_chars': len(toon_str),
            'json_tokens_est': json_tokens,
            'toon_tokens_est': toon_tokens,
            'savings_percent': round(savings, 1)
        }


# Convenience functions
def dumps(data: Any, name: str = 'data') -> str:
    """Convert Python object to TOON string"""
    return TOON.stringify(data, name)


def loads(toon: str) -> Dict:
    """Parse TOON string to Python object"""
    return TOON.parse(toon)


if __name__ == '__main__':
    # Demo
    sample_data = [
        {'id': 1, 'name': 'Alice', 'score': 95.5},
        {'id': 2, 'name': 'Bob', 'score': 87.0},
        {'id': 3, 'name': 'Charlie', 'score': 92.3}
    ]

    print("=== TOON Demo ===\n")
    print("Original JSON:")
    print(json.dumps(sample_data, indent=2))

    print("\nTOON format:")
    toon_output = TOON.stringify(sample_data, 'users')
    print(toon_output)

    print("\nParsed back:")
    parsed = TOON.parse(toon_output)
    print(json.dumps(parsed, indent=2))

    print("\nToken savings:")
    stats = TOON.token_savings(sample_data, 'users')
    print(f"  JSON: ~{stats['json_tokens_est']} tokens ({stats['json_chars']} chars)")
    print(f"  TOON: ~{stats['toon_tokens_est']} tokens ({stats['toon_chars']} chars)")
    print(f"  Savings: {stats['savings_percent']}%")

