            obj = {}
            for i, key in enumerate(keys):
                obj[key] = TOON._parse_value(values[i] if i < len(values) else None)
            return {name: obj}

    @staticmethod
    def _parse_line(line: str) -> List[str]:
        """Parse a single data line handling quoted values"""
        values = []
        current = ''
        in_quotes = False
        i = 0

        while i < len(line):
            char = line[i]

            if char == '"':
                if in_quotes and i + 1 < len(line) and line[i + 1] == '"':
                    current += '"'
                    i += 1
                else:
                    in_quotes = not in_quotes
            elif char == ',' and not in_quotes:
                values.append(current)
                current = ''
            else:
                current += char
            i += 1

        values.append(current)
        return values

    @staticmethod
    def _parse_value(val: Optional[str]) -> Any:
        """Parse individual value to appropriate Python type"""
        if val is None or val == '':
            return None
        if val == 'true':
            return True
        if val == 'false':
            return False
        if val == 'null':
            return None

        # Try parsing as number
        try:
            if '.' in val:
                return float(val)
            return int(val)
        except ValueError:
            pass

        # Try parsing as JSON (for nested objects)
        if (val.startswith('{') and val.endswith('}')) or \
           (val.startswith('[') and val.endswith(']')):
            try:
                return json.loads(val)
            except json.JSONDecodeError:
                pass

        return val

    @staticmethod
    def token_savings(data: Any, name: str = 'data') -> Dict[str, Any]:
        """
        Calculate token savings estimate.

        Args:
            data: Original Python data
            name: Collection name

        Returns:
            Dict with JSON size, TOON size, and savings percentage
        """
        json_str = json.dumps(data)
        toon_str = TOON.stringify(data, name)

        # Rough token estimate (chars / 4)
        json_tokens = len(json_str) // 4 + 1
        toon_tokens = len(toon_str) // 4 + 1
        savings = (json_tokens - toon_tokens) / json_tokens * 100

        return {
            'json_chars': len(json_str),
            'toon_chars': len(toon_str),
            'json_tokens_est': json_tokens,
            'toon_tokens_est': toon_tokens,
            'savings_percent': round(savings, 1)
        }


# Convenience functions
def dumps(data: Any, name: str = 'data') -> str:
    """Convert Python object to TOON string"""
    return TOON.stringify(data, name)


def loads(toon: str) -> Dict:
    """Parse TOON string to Python object"""
    return TOON.parse(toon)


